/**
 * Generate Short.io firewall config.
 *
 * Data source: https://developers.short.io/docs/cre
 *
 * Short.io is a URL shortening and link management platform.
 * Uses Bearer token authentication.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.short.io/docs/cre";
// Token format not publicly documented; using generic placeholder
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalC";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Short.io API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:shortio",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const shortioFirewall = {",
    '  name: "shortio",',
    '  description: "Short.io API",',
    "  placeholders: {",
    `    SHORTIO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.short.io",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SHORTIO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Short.io firewall config...");
  const ts = generateTypeScript();
  writeOutput("shortio", ts, import.meta.dirname);
}
